query:
-- Distribute users across 6 months (retroactive timestamps)
UPDATE users SET createdAt = DATE_SUB(NOW(), INTERVAL FLOOR(RAND() * 180) DAY) WHERE id > 0;

-- Distribute profiles across 6 months with growth curve (more recent = more profiles)
UPDATE profiles SET createdAt = DATE_SUB(NOW(), INTERVAL FLOOR(RAND() * 150) DAY) WHERE id <= 10;
UPDATE profiles SET createdAt = DATE_SUB(NOW(), INTERVAL FLOOR(RAND() * 120) DAY) WHERE id > 10 AND id <= 25;
UPDATE profiles SET createdAt = DATE_SUB(NOW(), INTERVAL FLOOR(RAND() * 90) DAY) WHERE id > 25 AND id <= 40;
UPDATE profiles SET createdAt = DATE_SUB(NOW(), INTERVAL FLOOR(RAND() * 60) DAY) WHERE id > 40 AND id <= 48;
UPDATE profiles SET createdAt = DATE_SUB(NOW(), INTERVAL FLOOR(RAND() * 30) DAY) WHERE id > 48;

-- Distribute offerings across 5 months
UPDATE offerings SET createdAt = DATE_SUB(NOW(), INTERVAL FLOOR(RAND() * 150) DAY) WHERE id <= 8;
UPDATE offerings SET createdAt = DATE_SUB(NOW(), INTERVAL FLOOR(RAND() * 90) DAY) WHERE id > 8 AND id <= 18;
UPDATE offerings SET createdAt = DATE_SUB(NOW(), INTERVAL FLOOR(RAND() * 45) DAY) WHERE id > 18;

-- Distribute opportunities across 4 months
UPDATE opportunities SET createdAt = DATE_SUB(NOW(), INTERVAL FLOOR(RAND() * 120) DAY) WHERE id <= 7;
UPDATE opportunities SET createdAt = DATE_SUB(NOW(), INTERVAL FLOOR(RAND() * 60) DAY) WHERE id > 7 AND id <= 14;
UPDATE opportunities SET createdAt = DATE_SUB(NOW(), INTERVAL FLOOR(RAND() * 30) DAY) WHERE id > 14;

-- Add critical performance indexes
CREATE INDEX IF NOT EXISTS idx_profiles_type_active ON profiles(profileType, isActive);
CREATE INDEX IF NOT EXISTS idx_profiles_state ON profiles(state);
CREATE INDEX IF NOT EXISTS idx_profiles_created ON profiles(createdAt);
CREATE INDEX IF NOT EXISTS idx_offerings_status_active ON offerings(status, isActive);
CREATE INDEX IF NOT EXISTS idx_offerings_created ON offerings(createdAt);
CREATE INDEX IF NOT EXISTS idx_opportunities_status ON opportunities(status, isActive);
CREATE INDEX IF NOT EXISTS idx_users_created ON users(createdAt);

